  server.registerTool("query", {
    title: "Hybrid Query (Best Quality)",
    description: "Full hybrid search (BM25 + vector + rerank). General-purpose \u2014 use when query type is unclear. WRONG: query('why did we decide X') \u2014 use intent_search instead. WRONG: query('what happened last session') \u2014 use session_log instead. Prefer memory_retrieve for auto-routing.",
    inputSchema: {
      query: exports_external.string().describe("Natural language query"),
      limit: exports_external.number().optional().default(10),
      minScore: exports_external.number().optional().default(0),
      collection: exports_external.string().optional().describe("Filter to collection (single name or comma-separated)"),
      compact: exports_external.boolean().optional().default(false).describe("Return compact results (id, path, title, score, snippet) instead of full content"),
      diverse: exports_external.boolean().optional().default(true).describe("Apply MMR diversity filter to reduce near-duplicate results"),
      intent: exports_external.string().optional().describe("Domain intent hint for disambiguation \u2014 steers expansion, reranking, chunk selection, and snippet extraction"),
      candidateLimit: exports_external.number().optional().default(30).describe("Max candidates reaching the reranker (default 30)")
    }
  }, async ({ query, limit, minScore, collection, compact, diverse, intent, candidateLimit }) => {
    const candLimit = candidateLimit || 30;
    const rankedLists = [];
    const docidMap = new Map;
    const hasVectors = !!store.db.prepare(`SELECT name FROM sqlite_master WHERE type='table' AND name='vectors_vec'`).get();
    const collections = collection ? collection.split(",").map((c) => c.trim()).filter(Boolean) : undefined;
    const initialFts = store.searchFTS(query, 20, undefined, collections);
    const topScore = initialFts.length > 0 ? Math.abs(initialFts[0].score) : 0;
    const secondScore = initialFts.length > 1 ? Math.abs(initialFts[1].score) : 0;
    const hasStrongSignal = !intent && initialFts.length > 0 && topScore >= 0.85 && topScore - secondScore >= 0.15;
    const queries = hasStrongSignal ? [query] : await store.expandQuery(query, DEFAULT_QUERY_MODEL, intent);
    for (const q of queries) {
      const ftsResults = q === query ? initialFts : store.searchFTS(q, 20, undefined, collections);
      if (ftsResults.length > 0) {
        for (const r of ftsResults)
          docidMap.set(r.filepath, r.docid);
        rankedLists.push(ftsResults.map((r) => ({ file: r.filepath, displayPath: r.displayPath, title: r.title, body: r.body || "", score: r.score })));
      }
      if (hasVectors) {
        const vecResults = await store.searchVec(q, DEFAULT_EMBED_MODEL, 20, undefined, collections);
        if (vecResults.length > 0) {
          for (const r of vecResults)
            docidMap.set(r.filepath, r.docid);
          rankedLists.push(vecResults.map((r) => ({ file: r.filepath, displayPath: r.displayPath, title: r.title, body: r.body || "", score: r.score })));
        }
      }
    }
    const weights = rankedLists.map((_, i) => i < 2 ? 2 : 1);
    const fused = reciprocalRankFusion(rankedLists, weights);
    const candidates = fused.slice(0, candLimit);
    const intentTerms = intent ? extractIntentTerms(intent) : [];
    const chunksToRerank = candidates.map((c) => {
      let text = c.body.slice(0, 4000);
      if (intentTerms.length > 0 && c.body.length > 4000) {
        const chunks = splitIntoWindows(c.body, 4000);
        let bestChunk = chunks[0];
        let bestScore = -1;
        const queryTerms = query.toLowerCase().split(/\s+/).filter((t) => t.length > 0);
        for (const chunk of chunks) {
          const lower = chunk.toLowerCase();
          let score = 0;
          for (const term of queryTerms) {
            if (lower.includes(term))
              score += 1;
          }
          for (const term of intentTerms) {
            if (lower.includes(term))
              score += INTENT_CHUNK_WEIGHT;
          }
          if (score > bestScore) {
            bestScore = score;
            bestChunk = chunk;
          }
        }
        text = bestChunk;
      }
      return { file: c.file, text };
    });
    const reranked = await store.rerank(query, chunksToRerank, DEFAULT_RERANK_MODEL2, intent);
    const candidateMap = new Map(candidates.map((c) => [c.file, c]));
    const rrfRankMap = new Map(candidates.map((c, i) => [c.file, i + 1]));
    const blended = reranked.map((r) => {
      const rrfRank = rrfRankMap.get(r.file) || candidates.length;
      const rrfWeight = rrfRank <= 3 ? 0.75 : rrfRank <= 10 ? 0.6 : 0.4;
      const blendedScore = rrfWeight * (1 / rrfRank) + (1 - rrfWeight) * r.score;
      return { file: r.file, score: blendedScore };
    });
    blended.sort((a, b) => b.score - a.score);
    const allSearchResults = [...store.searchFTS(query, 30)];
    const resultMap = new Map(allSearchResults.map((r) => [r.filepath, r]));
    const searchResults = blended.map((b) => {
      const r = resultMap.get(b.file) || candidateMap.get(b.file);
      if (!r)
        return null;
      return { ...r, score: b.score, filepath: b.file };
    }).filter((r) => r !== null);
    const coFn = (path) => store.getCoActivated(path);
    const enriched = enrichResults(store, searchResults, query);
    let scored = applyCompositeScoring(enriched, query, coFn).filter((r) => r.compositeScore >= (minScore || 0));
    if (diverse !== false)
      scored = applyMMRDiversity(scored);
    scored = scored.slice(0, limit || 10);
    if (compact) {
      const items2 = scored.map((r) => ({
        docid: `#${docidMap.get(r.filepath) || r.docid}`,
        path: r.displayPath,
        title: r.title,
        score: Math.round((r.compositeScore ?? r.score) * 100) / 100,
        snippet: (r.body || "").substring(0, 150),
        content_type: r.contentType,
        modified_at: r.modifiedAt,
        fragment: r.fragmentType ? { type: r.fragmentType, label: r.fragmentLabel } : undefined
      }));
      return { content: [{ type: "text", text: formatSearchSummary(items2.map((i) => ({ ...i, file: i.path, compositeScore: i.score, context: null })), query) }], structuredContent: { results: items2 } };
    }
    const items = scored.map((r) => {
      const { line, snippet } = extractSnippet(r.body || "", query, 300, r.chunkPos, intent);
      return {
        docid: `#${docidMap.get(r.filepath) || r.docid}`,
        file: r.displayPath,
        title: r.title,
        score: r.score,
        compositeScore: Math.round(r.compositeScore * 100) / 100,
        contentType: r.contentType,
        context: store.getContextForFile(r.filepath),
        snippet: addLineNumbers(snippet, line)
      };
    });
    return {
      content: [{ type: "text", text: formatSearchSummary(items, query) }],
      structuredContent: { results: items }
    };
  });
  server.registerTool("memory_forget", {
    title: "Forget Memory",
    description: "Remove a memory by searching for the closest match and deactivating it.",
    inputSchema: {
      query: exports_external.string().describe("What to forget \u2014 searches for the closest match"),
      confirm: exports_external.boolean().optional().default(true).describe("If true, deactivates the best match. If false, just shows what would be forgotten.")
    }
  }, async ({ query, confirm }) => {
    const results = store.searchFTS(query, 5);
    if (results.length === 0) {
      return { content: [{ type: "text", text: `No matching memory found for "${query}"` }] };
    }
    const best = results[0];
    const parts = best.displayPath.split("/");
    const collection = parts[0];
    const path = parts.slice(1).join("/");
    if (!confirm) {
      return {
        content: [{ type: "text", text: `Would forget: ${best.displayPath} \u2014 "${best.title}" (score ${Math.round(best.score * 100)}%)` }],
        structuredContent: { path: best.displayPath, title: best.title, score: best.score, action: "preview" }
      };
    }
    store.deactivateDocument(collection, path);
    store.insertUsage({
      sessionId: "mcp-forget",
      timestamp: new Date().toISOString(),
      hookName: "memory_forget",
      injectedPaths: [best.displayPath],
      estimatedTokens: 0,
      wasReferenced: 0
    });
    return {
      content: [{ type: "text", text: `Forgotten: ${best.displayPath} \u2014 "${best.title}"` }],
      structuredContent: { path: best.displayPath, title: best.title, action: "deactivated" }
    };
  });
  server.registerTool("profile", {
    title: "User Profile",
    description: "Get the current user profile (static facts + dynamic context). Rebuild if stale.",
    inputSchema: {
      rebuild: exports_external.boolean().optional().default(false).describe("Force rebuild the profile")
    }
  }, async ({ rebuild }) => {
    const { getProfile: gp, updateProfile: up, isProfileStale: ips } = await Promise.resolve().then(() => (init_profile(), exports_profile));
    if (rebuild || ips(store)) {
      up(store);
    }
    const profile = gp(store);
    if (!profile) {
      return { content: [{ type: "text", text: "No profile available. Try: profile(rebuild=true)" }] };
    }
    const lines = [];
    if (profile.static.length > 0) {
      lines.push("## Known Context");
      for (const f of profile.static)
        lines.push(`- ${f}`);
    }
    if (profile.dynamic.length > 0) {
      lines.push("", "## Current Focus");
      for (const d of profile.dynamic)
        lines.push(`- ${d}`);
    }
    return { content: [{ type: "text", text: lines.join(`
`) || "Profile is empty." }] };
  });
  server.registerTool("get", {
    title: "Get Document",
    description: "Retrieve document by file path or docid.",
    inputSchema: {
      file: exports_external.string().describe("File path or docid (#abc123)"),
      fromLine: exports_external.number().optional(),
      maxLines: exports_external.number().optional(),
      lineNumbers: exports_external.boolean().optional().default(false)
    }
  }, async ({ file: file2, fromLine, maxLines, lineNumbers }) => {
    let parsedFromLine = fromLine;
    let lookup = file2;
    const colonMatch = lookup.match(/:(\d+)$/);
    if (colonMatch?.[1] && parsedFromLine === undefined) {
      parsedFromLine = parseInt(colonMatch[1], 10);
      lookup = lookup.slice(0, -colonMatch[0].length);
    }
    const result = store.findDocument(lookup, { includeBody: false });
    if ("error" in result) {
      let msg = `Document not found: ${file2}`;
      if (result.similarFiles.length > 0) {
        msg += `

Did you mean?
${result.similarFiles.map((s) => `  - ${s}`).join(`
`)}`;
      }
      return { content: [{ type: "text", text: msg }], isError: true };
    }
    const body = store.getDocumentBody(result, parsedFromLine, maxLines) ?? "";
    let text = body;
    if (lineNumbers)
      text = addLineNumbers(text, parsedFromLine || 1);
    if (result.context)
      text = `<!-- Context: ${result.context} -->

` + text;
    return {
      content: [{
        type: "resource",
        resource: {
          uri: `clawmem://${encodeClawmemPath(result.displayPath)}`,
          name: result.displayPath,
          title: result.title,
          mimeType: "text/markdown",
          text
        }
      }]
    };
  });
  server.registerTool("multi_get", {
    title: "Multi-Get Documents",
    description: "Retrieve multiple documents by glob pattern or comma-separated list.",
    inputSchema: {
      pattern: exports_external.string().describe("Glob pattern or comma-separated paths"),
      maxLines: exports_external.number().optional(),
      maxBytes: exports_external.number().optional().default(10240),
      lineNumbers: exports_external.boolean().optional().default(false)
    }
  }, async ({ pattern, maxLines, maxBytes, lineNumbers }) => {
    const { docs, errors: errors4 } = store.findDocuments(pattern, { includeBody: true, maxBytes: maxBytes || DEFAULT_MULTI_GET_MAX_BYTES });
    if (docs.length === 0 && errors4.length === 0) {
      return { content: [{ type: "text", text: `No files matched: ${pattern}` }], isError: true };
    }
    const content = [];
    if (errors4.length > 0)
      content.push({ type: "text", text: `Errors:
${errors4.join(`
`)}` });
    for (const result of docs) {
      if (result.skipped) {
        content.push({ type: "text", text: `[SKIPPED: ${result.doc.displayPath} - ${result.skipReason}]` });
        continue;
      }
      let text = result.doc.body || "";
      if (maxLines !== undefined) {
        const lines = text.split(`
`);
        text = lines.slice(0, maxLines).join(`
`);
        if (lines.length > maxLines)
          text += `

[... truncated ${lines.length - maxLines} more lines]`;
      }
      if (lineNumbers)
        text = addLineNumbers(text);
      if (result.doc.context)
        text = `<!-- Context: ${result.doc.context} -->

` + text;
      content.push({
        type: "resource",
        resource: {
          uri: `clawmem://${encodeClawmemPath(result.doc.displayPath)}`,
          name: result.doc.displayPath,
          title: result.doc.title,
          mimeType: "text/markdown",
          text
        }
      });
    }
    return { content };
  });
