init_limits();
var MAX_TOKEN_BUDGET = 800;
var MAX_RESULTS = 10;
var MIN_COMPOSITE_SCORE = 0.45;
var MIN_COMPOSITE_SCORE_RECENCY = 0.35;
var SNIPPET_MAX_CHARS = 300;
