    prompt = prompt.slice(0, MAX_QUERY_LENGTH);
  if (prompt.startsWith("/"))
    return makeEmptyOutput("context-surfacing");
  if (shouldSkipRetrieval(prompt))
    return makeEmptyOutput("context-surfacing");
  if (isHeartbeatPrompt(prompt))
    return makeEmptyOutput("context-surfacing");
  if (wasPromptSeenRecently(store, "context-surfacing", prompt)) {
    return makeEmptyOutput("context-surfacing");
  }
  const isRecency = hasRecencyIntent(prompt);
  const minScore = isRecency ? MIN_COMPOSITE_SCORE_RECENCY : MIN_COMPOSITE_SCORE;
  let results = [];
  try {
    const vectorPromise = store.searchVec(prompt, DEFAULT_EMBED_MODEL, MAX_RESULTS);
    const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error("vector timeout")), 900));
    results = await Promise.race([vectorPromise, timeoutPromise]);
  } catch {}
  if (results.length === 0) {
    results = store.searchFTS(prompt, MAX_RESULTS);
  } else {
    const seen = new Set(results.map((r) => r.filepath));
    const ftsSupplemental = store.searchFTS(prompt, 5);
    for (const r of ftsSupplemental) {
      if (!seen.has(r.filepath)) {
        seen.add(r.filepath);
        results.push(r);
      }
    }
  }
  if (results.length === 0)
    return makeEmptyOutput("context-surfacing");
  results = results.filter((r) => !FILTERED_PATHS.some((p) => r.displayPath.includes(p)));
  if (results.length === 0)
    return makeEmptyOutput("context-surfacing");
  const now = new Date;
  results = results.filter((r) => {
    const parsed = r.filepath.startsWith("clawmem://") ? r.filepath.replace(/^clawmem:\/\/[^/]+\/?/, "") : r.filepath;
    const doc = store.findActiveDocument(r.collectionName, parsed);
    if (!doc)
      return true;
    if (doc.snoozed_until && new Date(doc.snoozed_until) > now)
      return false;
    return true;
  });
  if (results.length === 0)
    return makeEmptyOutput("context-surfacing");
  const deduped = new Map;
  for (const r of results) {
    const existing = deduped.get(r.filepath);
    if (!existing || r.score > existing.score) {
      deduped.set(r.filepath, r);
    }
  }
  results = [...deduped.values()];
  results = results.filter((r) => !r.body || !isRetrievedNoise(r.body));
  const enriched = enrichResults(store, results, prompt);
  const scored = applyCompositeScoring(enriched, prompt).filter((r) => r.compositeScore >= minScore);
